const { v4: uuidv4 } = global.get('uuid') || {};

// Store original HTTP request for response later
msg._res = msg.res;
msg._req = msg.req;

// Initialize trace array
msg.trace = [];
msg.startTime = Date.now();

// Preserve raw payload
msg.orderPayload = msg.payload;

return msg;

// EIP: Content-Based Router
// Routes message based on orderType field
const payload = msg.payload || {};
const contentType = msg.req && msg.req.headers && msg.req.headers['content-type'] || '';

let orderType = payload.orderType || payload.order_type || payload.type || 'standard';

// Detect B2B from content-type
if (contentType.includes('text/xml') || contentType.includes('application/xml')) {
    orderType = 'b2b';
}

msg.orderType = orderType.toLowerCase();
node.log('Routing order type: ' + msg.orderType);

// Route: 0 = standard, 1 = express, 2 = b2b
if (msg.orderType === 'express') return [null, msg, null];
if (msg.orderType === 'b2b') return [null, null, msg];
return [msg, null, null];

// EIP: Message Translator — normalize to canonical schema
const p = msg.payload;
msg.canonicalOrder = {
    orderType: 'standard',
    customerId: p.customerId || p.customer_id || 'unknown',
    items: p.items || [],
    totalAmount: p.totalAmount || p.total || 0,
    currency: p.currency || 'USD',
    raw: p
};
return msg;

// EIP: Message Translator — normalize mobile/express format
const p = msg.payload;
msg.canonicalOrder = {
    orderType: 'express',
    customerId: p.cust_id || p.customerId || 'unknown',
    items: p.items || (p.item ? [p.item] : []),
    totalAmount: p.amt || p.totalAmount || 0,
    currency: p.cur || p.currency || 'USD',
    raw: p
};
return msg;

// EIP: Message Translator — normalize B2B/EDI format
const p = msg.payload;
// XML may have been parsed or be a string
const data = (typeof p === 'object') ? p : {};
msg.canonicalOrder = {
    orderType: 'b2b',
    customerId: data.customerId || data.buyer || 'b2b-client',
    items: data.items || data.lineItems || [],
    totalAmount: data.totalAmount || data.amount || 0,
    currency: data.currency || 'USD',
    raw: p
};
return msg;

const orderUrl = env.get('ORDER_URL') || 'http://order-service:3001';

msg.method = 'POST';
msg.url = orderUrl + '/orders';
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = {
    ...msg.canonicalOrder,
    orderType: msg.orderType
};
return msg;

const body = msg.payload;
const statusCode = msg.statusCode;

if (statusCode !== 201 || !body.orderId) {
    msg.errorStep = 'order';
    msg.errorReason = body.error || 'Order creation failed';
    return [null, msg];
}

// EIP: Correlation Identifier — carry correlationId through entire flow
msg.orderId = body.orderId;
msg.correlationId = body.correlationId;
msg.trace = msg.trace || [];

return [msg, null];

const paymentUrl = env.get('PAYMENT_URL') || 'http://payment-service:3002';

msg._paymentStart = Date.now();
msg.method = 'POST';
msg.url = paymentUrl + '/payment/authorize';
msg.headers = {
    'Content-Type': 'application/json',
    'X-Correlation-Id': msg.correlationId
};
msg.payload = {
    orderId: msg.orderId,
    correlationId: msg.correlationId,
    amount: msg.canonicalOrder ? msg.canonicalOrder.totalAmount : 0,
    currency: msg.canonicalOrder ? msg.canonicalOrder.currency : 'USD'
};
return msg;

const body = msg.payload;
const durationMs = Date.now() - (msg._paymentStart || Date.now());

if (body.status === 'authorized') {
    msg.transactionId = body.transactionId;
    msg.trace.push({ step: 'payment', status: 'success', durationMs });
    return [msg, null];
} else {
    msg.trace.push({ step: 'payment', status: 'failed', durationMs });
    msg.errorStep = 'payment';
    msg.errorReason = body.reason || 'Payment rejected';
    return [null, msg];
}

const inventoryUrl = env.get('INVENTORY_URL') || 'http://inventory-service:3003';

msg._inventoryStart = Date.now();
msg.method = 'POST';
msg.url = inventoryUrl + '/inventory/reserve';
msg.headers = {
    'Content-Type': 'application/json',
    'X-Correlation-Id': msg.correlationId
};
msg.payload = {
    orderId: msg.orderId,
    correlationId: msg.correlationId,
    items: msg.canonicalOrder ? msg.canonicalOrder.items : []
};
return msg;

const body = msg.payload;
const durationMs = Date.now() - (msg._inventoryStart || Date.now());

if (body.status === 'reserved') {
    msg.reservationId = body.reservationId;
    msg.trace.push({ step: 'inventory', status: 'success', durationMs });
    return [msg, null];
} else {
    msg.trace.push({ step: 'inventory', status: 'failed', durationMs });
    msg.errorStep = 'inventory';
    msg.errorReason = body.reason || 'Inventory unavailable';
    return [null, msg];
}

const notificationUrl = env.get('NOTIFICATION_URL') || 'http://notification-service:3004';

msg._notificationStart = Date.now();
msg.method = 'POST';
msg.url = notificationUrl + '/notification/send';
msg.headers = {
    'Content-Type': 'application/json',
    'X-Correlation-Id': msg.correlationId
};
msg.payload = {
    orderId: msg.orderId,
    correlationId: msg.correlationId,
    type: 'order_confirmed',
    message: 'Your order has been confirmed and payment processed.'
};
return msg;

const body = msg.payload;
const durationMs = Date.now() - (msg._notificationStart || Date.now());

if (body.status === 'sent') {
    msg.trace.push({ step: 'notification', status: 'success', durationMs });
    return [msg, null];
} else {
    msg.trace.push({ step: 'notification', status: 'failed', durationMs });
    msg.errorStep = 'notification';
    msg.errorReason = 'Notification failed';
    return [null, msg];
}

msg.statusCode = 200;
msg.payload = {
    orderId: msg.orderId,
    correlationId: msg.correlationId,
    status: 'completed',
    trace: msg.trace || []
};
return msg;

msg.statusCode = 200;
msg.payload = {
    orderId: msg.orderId || null,
    correlationId: msg.correlationId || null,
    status: 'failed',
    reason: msg.errorReason || 'Unknown error',
    trace: msg.trace || []
};
return msg;

// EIP: Compensation — reverse of inventory reserve
const inventoryUrl = env.get('INVENTORY_URL') || 'http://inventory-service:3003';

msg.method = 'POST';
msg.url = inventoryUrl + '/inventory/release';
msg.headers = {
    'Content-Type': 'application/json',
    'X-Correlation-Id': msg.correlationId
};
msg.payload = {
    orderId: msg.orderId,
    correlationId: msg.correlationId,
    reservationId: msg.reservationId
};
return msg;

// EIP: Compensation — reverse of payment authorize
const paymentUrl = env.get('PAYMENT_URL') || 'http://payment-service:3002';

msg.method = 'POST';
msg.url = paymentUrl + '/payment/refund';
msg.headers = {
    'Content-Type': 'application/json',
    'X-Correlation-Id': msg.correlationId
};
msg.payload = {
    orderId: msg.orderId,
    correlationId: msg.correlationId,
    transactionId: msg.transactionId
};
return msg;

msg.trace.push({ step: 'compensation:payment-refund', status: 'success' });

msg.statusCode = 200;
msg.payload = {
    orderId: msg.orderId || null,
    correlationId: msg.correlationId || null,
    status: 'compensated',
    reason: msg.errorReason || 'Downstream failure',
    trace: msg.trace || []
};
return msg;

// EIP: Dead Letter Channel
// Captures unrecoverable messages for manual inspection
const deadLetters = global.get('deadLetters') || [];
deadLetters.push({
    timestamp: new Date().toISOString(),
    correlationId: msg.correlationId,
    orderId: msg.orderId,
    error: msg.errorReason || 'unknown',
    payload: msg.payload
});
global.set('deadLetters', deadLetters);
node.warn('Dead letter captured: ' + msg.correlationId);
return msg;

msg.payload = { status: 'ok', service: 'node-red' };
msg.statusCode = 200;
return msg;

const deadLetters = global.get('deadLetters') || [];
const orderId = msg.req.params.orderId;
const found = deadLetters.filter(d => d.orderId === orderId);
msg.payload = { orderId, deadLetters: found };
msg.statusCode = 200;
return msg;
